import html
import re
from xml.etree import ElementTree

from relocation_jobs.core.ats_detection import HEADERS
from relocation_jobs.scrape.boards._async import run_sync
from relocation_jobs.scrape.listing import listing_job

DEFAULT_REMOTEDXB_RSS = "https://www.remotedxb.com/rss"
_NS = {"rd": "https://www.remotedxb.com/rss"}
_TAG_RE = re.compile(r"<[^>]+>")

_IT_CATEGORIES = frozenset({
    "information technology",
    "engineering & architecture",
    "engineering and architecture",
})


def remotedxb_feed_url(board_url: str) -> str:
    raw = (board_url or "").strip()
    if not raw:
        return DEFAULT_REMOTEDXB_RSS
    lower = raw.lower()
    if "remotedxb.com" not in lower:
        return DEFAULT_REMOTEDXB_RSS
    if lower.rstrip("/").endswith("/rss") or "rss" in lower:
        return raw.split("?")[0].rstrip("/") if raw.rstrip("/").endswith("/rss") else (
            "https://www.remotedxb.com/rss"
        )
    return DEFAULT_REMOTEDXB_RSS


def _plain_text(raw: str) -> str:
    text = html.unescape(raw or "")
    text = _TAG_RE.sub(" ", text)
    return re.sub(r"\s+", " ", text).strip()


def _item_text(item: ElementTree.Element, path: str) -> str:
    node = item.find(path)
    if node is not None and (node.text or "").strip():
        return (node.text or "").strip()
    node = item.find(path, _NS)
    if node is not None and (node.text or "").strip():
        return (node.text or "").strip()
    return ""


def parse_remotedxb_rss(feed_xml: str) -> list[dict]:
    text = (feed_xml or "").lstrip("\ufeff").strip()
    xml_start = text.find("<?xml")
    if xml_start > 0:
        text = text[xml_start:]
    if not text:
        return []
    root = ElementTree.fromstring(text.encode("utf-8"))
    jobs: list[dict] = []
    for item in root.findall(".//item"):
        title = _item_text(item, "title")
        link = _item_text(item, "link")
        employer = _item_text(item, "rd:companyName") or _item_text(
            item, "{https://www.remotedxb.com/rss}companyName"
        )
        category = _item_text(item, "category")
        if category and category.casefold() not in _IT_CATEGORIES:
            continue
        if not title or not link or not employer:
            continue
        description = _plain_text(_item_text(item, "description"))
        jobs.append(
            listing_job(
                title,
                link,
                location="Completely Remote",
                employer=employer,
                description_text=description or None,
            )
        )
    return jobs


def fetch_remotedxb_board_sync(feed_url: str) -> list[dict]:
    import requests

    url = remotedxb_feed_url(feed_url)
    response = requests.get(url, headers=HEADERS, timeout=30)
    response.raise_for_status()
    return parse_remotedxb_rss(response.text)


async def fetch_remotedxb_board(client, board_url: str, company: dict) -> list[dict]:
    url = board_url or (company.get("ats_url") or company.get("careers_url") or "")
    return await run_sync(fetch_remotedxb_board_sync, url)

from __future__ import annotations

from collections import defaultdict
from datetime import date

from relocation_jobs.catalog.repo import sync_aggregator_employer_jobs
from relocation_jobs.fetch.log import log_event
from relocation_jobs.scrape.filter import filter_relevant_jobs

AGGREGATOR_ATS_TYPES = frozenset({"remoteok", "remotedxb"})
SOURCED_ATS_TYPE = "sourced"

_SOURCE_LABEL = {
    "remoteok": "remoteok",
    "remotedxb": "remotedxb",
}


def is_aggregator_ats(ats_type: str | None) -> bool:
    return (ats_type or "").strip().lower() in AGGREGATOR_ATS_TYPES


def should_skip_country_fetch(ats_type: str | None) -> bool:
    return (ats_type or "").strip().lower() == SOURCED_ATS_TYPE


def group_jobs_by_employer(jobs: list[dict]) -> dict[str, list[dict]]:
    grouped: dict[str, list[dict]] = defaultdict(list)
    for job in jobs:
        employer = (job.get("employer") or "").strip()
        if not employer:
            continue
        entry = {
            "title": (job.get("title") or "").strip(),
            "url": (job.get("url") or "").strip(),
        }
        location = (job.get("location") or "").strip()
        if location:
            entry["location"] = location
        if job.get("locations") is not None:
            entry["locations"] = job["locations"]
        description = (job.get("description_text") or "").strip()
        if description:
            entry["description_text"] = description
        if entry["title"] and entry["url"]:
            grouped[employer].append(entry)
    return dict(grouped)


def sync_aggregator_board(
    country_key: str,
    source_company: dict,
    raw_jobs: list[dict],
    *,
    relevant_only: bool = True,
) -> tuple[int, int]:
    ats = (source_company.get("ats_type") or "").strip().lower()
    source = _SOURCE_LABEL.get(ats, ats or "aggregator")
    matched = filter_relevant_jobs(raw_jobs, relevant_only)
    grouped = group_jobs_by_employer(matched)
    employers = 0
    job_total = 0
    careers_fallback = (
        (source_company.get("careers_url") or source_company.get("ats_url") or "").strip()
    )
    for employer, jobs in grouped.items():
        if not jobs:
            continue
        sync_aggregator_employer_jobs(
            country_key,
            employer,
            jobs,
            source=source,
            careers_url=careers_fallback or jobs[0]["url"],
        )
        employers += 1
        job_total += len(jobs)
    log_event(
        f"aggregator sync employers={employers} jobs={job_total}",
        company=source_company.get("name") or "",
    )
    return employers, job_total


def aggregator_success_line(prefix: str, employers: int, jobs: int) -> str:
    return f"{prefix} — aggregator: {jobs} job(s) across {employers} employer(s)"


def today_iso() -> str:
    return date.today().isoformat()

